  ('aboriginal-a5729396-moex-00430', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '原住民族基本法中與部落有關之規範，以下敘述何者錯誤？', '["部落指原住民於原住民族地區一定區域內，依傳統規範共同生活結合而成之團體，經中央原住民族 主管機關核定者", "部落之核定、組織、部落會議之組成、決議程序及其他相關事項之辦法，由中央原住民族主管機關 定之", "政府於原住民族地區，應依原住民族意願，回復原住民族部落及山川傳統名稱", "政府辦理公務人員特種考試原住民族考試，得於相關法令規定優先分發至該原住民族公務人員所屬 部落"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00431', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '關於族語能力認證之現行制度，以下敘述何者錯誤？', '["族語能力認證分為初級、中級、中高級、高級及優級", "族語能力認證得委託學校或民間團體辦理認證工作", "族語能力認證之參加者須為本國籍，不受族別及年齡之限制", "族語能力認證方式包括測驗、審查兩類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00432', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '為促進原住民就業，保障原住民工作權及經濟生活，以下敘述何者錯誤？', '["原住民族工作權保障法保障對象為居住於原住民族地區以外之都市原住民", "各級政府機關、公立學校及公營事業機構應依循比例進用原則僱用原住民", "政府應依原住民群體工作習性，輔導原住民設立各種性質之原住民合作社", "依政府採購法得標之廠商，於國內員工總人數逾一百人者，應於履約期間僱用原住民"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
